 42	
 43	const S3BucketDetailsOverview: React.FC<{}> = ({}) => {
 44	  const { t } = useCustomTranslation();
 45	  const { s3Client } = React.useContext(S3Context);
 46	  const { bucketName } = useParams();
 47	  const input = { Bucket: bucketName };
 48	  const { data: aclData } = useSWR(
 49	    `${s3Client.providerType}-${bucketName}-${BUCKET_ACL_CACHE_KEY_SUFFIX}`,
 50	    () => s3Client.getBucketAcl(input)
 51	  );
 52	  const { data: tagData } = useSWR(
 53	    `${s3Client.providerType}-${bucketName}-${BUCKET_TAGGING_CACHE_KEY_SUFFIX}`,
 54	    () => s3Client.getBucketTagging(input)
 55	  );
 56	
 57	  const tags = tagData?.TagSet?.map((tag: Tag) => (
 58	    <Label className="pf-v6-u-mr-xs" color="grey" icon={<TagIcon />}>
 59	      {tag.Key}
 60	      {tag.Value && `=${tag.Value}`}
 61	    </Label>
 62	  ));
 63	
 64	  return (
 65	    <div className="odf-m-pane__body">
 66	      <SectionHeading text={t('Bucket overview')} />
 67	      <div className="row">
 68	        <div className="col-sm-6">
 69	          <DescriptionList>
 70	            <DescriptionListGroup>
 71	              <DescriptionListTerm>{t('Name')}</DescriptionListTerm>
 72	              <DescriptionListDescription>
 73	                {bucketName}
 74	              </DescriptionListDescription>
 75	            </DescriptionListGroup>
 76	
 77	            <DescriptionListGroup>
 78	              <DescriptionListTerm>{t('Tags')}</DescriptionListTerm>
 79	              <DescriptionListDescription>
 80	                <LabelGroup>{tags || DASH}</LabelGroup>
 81	              </DescriptionListDescription>
 82	            </DescriptionListGroup>
 83	
 84	            <DescriptionListGroup>
 85	              <DescriptionListTerm>{t('Owner')}</DescriptionListTerm>
 86	              <DescriptionListDescription>
 87	                {aclData?.Owner?.DisplayName || DASH}
 88	              </DescriptionListDescription>
 89	            </DescriptionListGroup>
 90	          </DescriptionList>
 91	        </div>
 92	      </div>
 93	    </div>
 94	  );
 95	};
