 97	const S3BucketProperties: React.FC<{}> = ({}) => {
 98	  const { t } = useCustomTranslation();
 99	  const { s3Client } = React.useContext(S3Context);
100	  const { bucketName } = useParams();
101	  const input = { Bucket: bucketName };
102	  const { data: versioningData, mutate: versioningMutate } = useSWR(
103	    `${s3Client.providerType}-${bucketName}-${BUCKET_VERSIONING_CACHE_KEY_SUFFIX}`,
104	    () => s3Client.getBucketVersioning(input)
105	  );
106	
107	  const [isVersioningChecked, setIsVersioningChecked] =
108	    React.useState<boolean>(false);
109	
110	  const versioningStatus = getVersioningStatus(versioningData, t);
111	  const isVersioningEnabled = getIsVersioningEnabled(versioningData);
112	
113	  const launcher = useModal();
114	
115	  React.useEffect(
116	    () => setIsVersioningChecked(isVersioningEnabled),
117	    [isVersioningEnabled, setIsVersioningChecked]
118	  );
119	
120	  return (
121	    <div className="odf-m-pane__body">
122	      <SectionHeading text={t('Bucket properties')} />
123	      <Level>
124	        <LevelItem>
125	          <TextContent>
126	            <Text component={TextVariants.h4}>{t('Versioning')}</Text>
127	            <Text component={TextVariants.small}>
128	              {t(
129	                'Versioning helps in keeping multiple version of an object in the bucket.'
130	              )}
131	            </Text>
132	          </TextContent>
133	        </LevelItem>
134	        <LevelItem>
135	          <Switch
136	            id="versioning-switch"
137	            label={versioningStatus}
138	
139	            isChecked={isVersioningChecked}
140	            onChange={(_event, checked) =>
141	              launcher(SetVersioningModal, {
142	                extraProps: {
143	                  mutate: versioningMutate,
144	                  s3Client,
145	                  bucketName,
146	                  enableVersioning: checked,
147	                } as SetVersioningModalModalProps,
148	                isOpen: true,
149	              })
150	            }
151	          />
152	        </LevelItem>
153	      </Level>
154	    </div>
155	  );
156	};
157	
158	type BucketDetailsProps = {
159	  obj: {
160	    fresh: boolean;
161	    resource?: K8sResourceCommon;
162	  };
163	};
164	
165	export const BucketDetails: React.FC<BucketDetailsProps> = ({
166	  obj: { resource, fresh },
167	}) => {
168	  const { t } = useCustomTranslation();
169	  return fresh ? (
170	    <>
171	      <S3BucketDetailsOverview />
172	      <S3BucketProperties />
173	      {resource && (
174	        <ObjectBucketDetails
175	          obj={resource}
176	          ownerLabel={t('Owner References')}
177	        />
178	      )}
179	    </>
180	  ) : (
181	    <LoadingBox />
182	  );
183	};

